function filterTweets(tweet) {
  const author = tweet.user.screen_name;
  const text = tweet.text.toLowerCase();
  const hashtags = tweet.entities.hashtags.map(h => h.text.toLowerCase());

  if (author === 'antonio_garcia_trevijano' && text.length <= 280) {
    const dayOfWeek = new Date().getDay();
    let politicalHashtag;

    switch (dayOfWeek) {
      case 0: // Sunday
        politicalHashtag = '#sundaypolitics';
        break;
      case 1: // Monday
        politicalHashtag = '#mondaypolitics';
        break;
      case 2: // Tuesday
        politicalHashtag = '#tuesdaypolitics';
        break;
      case 3: // Wednesday
        politicalHashtag = '#wednesdaypolitics';
        break;
      case 4: // Thursday
        politicalHashtag = '#thursdaypolitics';
        break;
      case 5: // Friday
        politicalHashtag = '#fridaypolitics';
        break;
      case 6: // Saturday
        politicalHashtag = '#saturdaypolitics';
        break;
      default:
        return null; // Not a valid day of the week
    }

    if (!hashtags.includes(politicalHashtag)) {
      return { ...tweet, text: `${text} ${politicalHashtag}` };
    }
  }

  return null;
}
