```javascript
const buffer = require('buffer');
const moment = require('moment');

function generateRandomImage() {
  const sources = ['server', 'unsplash'];
  const source = sources[Math.floor(Math.random() * sources.length)];
  if (source === 'server') {
    return `https://your-server.com/image-${Math.floor(Math.random() * 100)}.jpg`;
  } else {
    return `https://source.unsplash.com/random/800x600`;
  }
}

function generateRandomQuote() {
  const quotes = [
    { text: "Believe you can and you're halfway there.", author: "Theodore Roosevelt" },
    { text: "It does not matter how slowly you go as long as you do not stop.", author: "Confucius" },
    { text: "Success is not final, failure is not fatal: It is the courage to continue that counts.", author: "Winston Churchill" },
    // Add more quotes here
  ];
  return quotes[Math.floor(Math.random() * quotes.length)];
}

function generateMessage(quote) {
  return `${quote.text}\n\n#Motivation #Inspiration #${quote.author.replace(/\s+/g, '').toLowerCase()}`;
}

function schedulePost(bufferClient, interval) {
  setInterval(() => {
    const image = generateRandomImage();
    const quote = generateRandomQuote();
    const message = generateMessage(quote);
    bufferClient.queue({
      image,
      text: message,
      link: null,
      via: null,
      visibility: 'public',
      scheduled_at: moment().add(interval, 'hours').unix()
    });
  }, interval * 3600000); // Convert hours to milliseconds
}

module.exports = schedulePost;
```

This code defines functions to generate random images from either a server or Unsplash, a random quote, and a formatted message. It then schedules a post on Buffer every specified interval using the provided Buffer client. The `schedulePost` function sets up an interval that triggers the posting process at the specified intervals.

